function buildStrategicDecisionPrompt(ctx, bundle) {
  const addendum = `
WORKFLOW #1 — DAILY CONTENT ENGINE, STRATEGIC DECISION PHASE

You are acting as the Head of Content Strategy at a senior agency, planning
today's content for ${ctx.businessName}.

Do NOT jump to tactics. Answer these strategic questions IN ORDER, showing
your reasoning explicitly:

  1. WHERE is this brand in its maturity journey?
     (Early / Growth / Mature / Incumbent — this dictates content balance.)
  2. WHAT narrative arc are we in this quarter?
     (Launch / Scale / Reposition / Defend / Expand.)
  3. WHAT is the cultural opportunity TODAY?
     - Trending topic we can authentically join?
     - Seasonal moment to claim?
     - Competitor weakness to exploit?
     - White space to claim?
     If none are strong, say so and design from first principles.
  4. WHICH funnel stages need attention?
     Look at pipeline state + 30-day mix. Are we TOFU-starved? BOFU-ready?
  5. WHICH content pillars are under-served?
     Compare pillarMixStatus target vs actual30d. Rebalance explicitly.
  6. WHICH emotions should today's content evoke?
     Choose 1–2 from: curiosity, aspiration, belonging, relief, pride, FOMO,
     nostalgia, hope, vindication. Justify WHY these and not others.

Then design 1–3 content concepts for today. Each concept MUST include:

  - platform: one of instagram_reel, instagram_story, instagram_feed, tiktok,
              linkedin, facebook, twitter, youtube_shorts, gbp_post
  - format:   specific format within platform (e.g. "9:16 Reel 7–15s", "PDF carousel 8 slides")
  - pillar:   which content pillar it serves
  - funnelStage: tofu | mofu | bofu | retention
  - emotion:  the primary emotional beat
  - coreIdea: one sentence — the concept in plain English
  - hook:     first 3 seconds (or first line for text posts). Use one of the
              validated hook patterns: Pattern Interrupt, Curiosity Gap,
              Value Promise, Contrarian, Storytelling. NAME which pattern.
  - storyArc: if video/carousel, the beat-by-beat arc
  - cta:      specific action you want the audience to take
  - framework: which psychology lever is load-bearing (Cialdini principle,
               StoryBrand role, Kahneman bias, JTBD job). One or two max —
               NOT a laundry list. Say WHY it's load-bearing here.
  - whyThisWhyNow: 2 sentences connecting this concept to the cultural,
                   competitive, and pillar-mix state above
  - predictedEngagementRange: [low, high] as decimal (e.g. [0.03, 0.06] = 3–6%)
  - riskLevel: low | medium | high — high = experimental, off-pillar, trend-chasing
  - costEstimate: USD, realistic ($0.15 image / $0.35 carousel / $0.65 reel /
                  $0.45 tiktok / $0.25 linkedin article)

OUTPUT FORMAT: strict JSON matching this TypeScript type:

  {
    "analysis": {
      "brandMaturity": "early" | "growth" | "mature" | "incumbent",
      "narrativeArc": "launch" | "scale" | "reposition" | "defend" | "expand",
      "culturalOpportunity": string,  // 2–3 sentences naming the opportunity (or "none — designing from first principles")
      "funnelStagesNeedingAttention": ("tofu" | "mofu" | "bofu" | "retention")[],
      "underservedPillars": string[],
      "targetEmotions": string[],
      "reasoning": string  // 4–6 sentences, senior-strategist voice — this is shown to the client in the approval UI
    },
    "concepts": [ /* 1–3 concepts as specified above */ ]
  }

HARD REQUIREMENTS
- Concepts MUST respect the 80/20 value/ask ratio (max 1 of 3 may be promotional).
- Must pass the LTV:CAC sanity check (no campaigns violating Principle 3).
- Must respect crisis/holiday sensitivity (no food promo during Ramadan daylight
  in Muslim-majority markets; no non-essential content during major tragedies).
- Must respect topic cooldown: no topic repeated within 7 days unless trending
  with <24h half-life (then flag explicitly).
- Must respect platform-optimal daily limits (max 3/platform/day, min 4h spacing).
- NEVER fabricate metrics. If predicting, base on this account's historical
  performance and industry benchmarks cited in INDUSTRY_PLAYBOOKS.
- If no strong concept is possible today, return { "concepts": [] } with
  reasoning — skipping a day is better than posting weak content.
`.trim();

  const user = `
DAILY CONTEXT BUNDLE (${bundle.cultural.todayLocalDate})

BRAND MEMORY
Voice: ${bundle.brandMemory.voiceProfile}
Winning patterns (top ${bundle.brandMemory.historicalWinners.length}):
${bundle.brandMemory.historicalWinners.map(w => `  • [${w.format}] "${w.hook}" — ${w.trait} — +${Math.round(w.engagementLift * 100)}% vs baseline`).join('\n')}

Anti-patterns to avoid:
${bundle.brandMemory.antiPatterns.map(a => `  • ${a.reason}: ${a.example}`).join('\n')}

Pillar mix (target vs actual 30d):
${bundle.brandMemory.pillarMixStatus.map(p => `  • ${p.pillar}: ${p.target}% target / ${p.actual30d}% actual ${p.actual30d < p.target ? '⬇ UNDER' : p.actual30d > p.target ? '⬆ OVER' : '= on target'}`).join('\n')}

PERFORMANCE (last 30d)
${bundle.performance.last30d.map(p => `  • ${p.platform}: ${p.posts} posts, ${(p.avgEngagement * 100).toFixed(1)}% avg eng (${p.vsBenchmark > 0 ? '+' : ''}${(p.vsBenchmark * 100).toFixed(0)}% vs industry benchmark)`).join('\n')}
Growth: follower Δ30d = ${bundle.performance.growthTrajectory.followerDelta30d > 0 ? '+' : ''}${bundle.performance.growthTrajectory.followerDelta30d}; engagement trend = ${bundle.performance.growthTrajectory.engagementTrend}
Saturation/fatigue score: ${bundle.performance.saturationFatigueScore}/100

CULTURAL
Upcoming holidays:
${bundle.cultural.upcomingHolidays.map(h => `  • ${h.date} — ${h.name} (${h.type})`).join('\n') || '  (none)'}
${bundle.cultural.seasonalMoment ? `Seasonal moment: ${bundle.cultural.seasonalMoment}\n` : ''}
Trending topics:
${bundle.cultural.trendingTopics.map(t => `  • [${t.platform}] ${t.topic} — velocity=${t.velocity}, relevance=${t.relevance}/10`).join('\n') || '  (none relevant)'}
News cycle:
${bundle.cultural.newsCycle.map(n => `  • ${n.headline} (${n.source}, relevance ${n.relevance}/10)`).join('\n') || '  (none relevant)'}

COMPETITIVE (last 24h)
${bundle.competitive.last24h.map(c => `  • ${c.competitor} [${c.platform}] "${c.topic}" — ${c.format}, est. engagement ${(c.estimatedEngagement * 100).toFixed(1)}%`).join('\n') || '  (quiet)'}
Gap opportunities: ${bundle.competitive.gapOpportunities.join(' | ') || '(none)'}
White space:       ${bundle.competitive.whiteSpace.join(' | ') || '(none)'}

AUDIENCE (last 48h)
${bundle.audience.topComments48h.map(c => `  • [${c.platform}] ${c.topic} — sentiment=${c.sentiment.toFixed(2)}, volume=${c.volume}`).join('\n') || '  (quiet)'}
Demographic shifts: ${bundle.audience.demographicShifts ?? 'none detected'}
Drop-off signals: ${bundle.audience.dropOffSignals.join('; ') || 'none'}

BUSINESS
Active campaigns:
${bundle.business.activeCampaigns.map(c => `  • ${c.name} (${c.funnelStage}) ends ${c.endsAt}`).join('\n') || '  (none)'}
${bundle.business.inventoryOrPromoCalendar ? `Inventory/promo: ${bundle.business.inventoryOrPromoCalendar}\n` : ''}
${bundle.business.salesPriorities?.length ? `Sales priorities: ${bundle.business.salesPriorities.join('; ')}\n` : ''}
${bundle.business.launchPipeline?.length ? `Launch pipeline:\n${bundle.business.launchPipeline.map(l => `  • ${l.name} — T-${l.daysUntil}d`).join('\n')}\n` : ''}
`.trim();

  return {
    system: buildSystemPrompt(ctx, addendum),
    user,
  };
}

